from itertools import combinations
class Solution:
    def minLength(self, s, numOps):
        n = len(s)
        def max_run(t):
            best = 1
            cur = 1
            for i in range(1, len(t)):
                if t[i] == t[i - 1]:
                    cur += 1
                    best = max(best, cur)
                else:
                    cur = 1
            return best
        best = max_run(s)
        for k in range(1, numOps + 1):
            for combo in combinations(range(n), k):
                t = list(s)
                for idx in combo:
                    t[idx] = '1' if t[idx] == '0' else '0'
                best = min(best, max_run(t))
        return best

