from collections import deque
class Solution:
    def minLength(self, s, numOps):
        n = len(s)
        ones = [0] * (n + 1)
        for i, ch in enumerate(s):
            ones[i + 1] = ones[i] + (1 if ch == '1' else 0)
        def feasible(L):
            dp0 = [0] * (n + 1)
            dp1 = [0] * (n + 1)
            dq0 = deque([(0, dp1[0] - ones[0])])
            dq1 = deque([(0, dp0[0] - (0 - ones[0]))])
            def push(dq, j, val):
                while dq and dq[-1][1] >= val:
                    dq.pop()
                dq.append((j, val))
            def popold(dq, lo):
                while dq and dq[0][0] < lo:
                    dq.popleft()
            for i in range(1, n + 1):
                lo = i - L
                popold(dq0, lo)
                popold(dq1, lo)
                dp0[i] = ones[i] + dq0[0][1]
                dp1[i] = (i - ones[i]) + dq1[0][1]
                push(dq0, i, dp1[i] - ones[i])
                push(dq1, i, dp0[i] - (i - ones[i]))
            return min(dp0[n], dp1[n])
        lo, hi = 1, n
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid) <= numOps:
                hi = mid
            else:
                lo = mid + 1
        return lo

