var minLength = function(s, numOps) {
    const n = s.length;
    const ones = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) ones[i + 1] = ones[i] + (s[i] === '1' ? 1 : 0);
    function feasible(L) {
        const dp0 = new Array(n + 1).fill(0);
        const dp1 = new Array(n + 1).fill(0);
        const idx0 = new Array(n + 2), val0 = new Array(n + 2);
        const idx1 = new Array(n + 2), val1 = new Array(n + 2);
        let h0 = 0, t0 = 0, h1 = 0, t1 = 0;
        idx0[0] = 0; val0[0] = dp1[0] - ones[0]; t0 = 1;
        idx1[0] = 0; val1[0] = dp0[0] - (0 - ones[0]); t1 = 1;
        for (let i = 1; i <= n; i++) {
            const lo = i - L;
            while (h0 < t0 && idx0[h0] < lo) h0++;
            while (h1 < t1 && idx1[h1] < lo) h1++;
            dp0[i] = ones[i] + val0[h0];
            dp1[i] = (i - ones[i]) + val1[h1];
            const v0 = dp1[i] - ones[i];
            while (t0 > h0 && val0[t0 - 1] >= v0) t0--;
            idx0[t0] = i; val0[t0] = v0; t0++;
            const v1 = dp0[i] - (i - ones[i]);
            while (t1 > h1 && val1[t1 - 1] >= v1) t1--;
            idx1[t1] = i; val1[t1] = v1; t1++;
        }
        return Math.min(dp0[n], dp1[n]);
    }
    let lo = 1, hi = n;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (feasible(mid) <= numOps) hi = mid; else lo = mid + 1;
    }
    return lo;
};
